#include "kvant/operations/settlement.hpp"
#include <algorithm>
#include <stdexcept>
namespace kvant::operations {long long Calendar::add_business_days(long long d,int n)const{while(n>0){++d;int weekday=static_cast<int>((d+4)%7);if(weekday!=0&&weekday!=6&&!holidays.count(d))--n;}return d;}void SettlementBook::configure(Convention c,Calendar k){if(c.business_days<0)throw std::invalid_argument("settlement days");auto key=std::make_pair(c.market,c.currency);config_[key]={std::move(c),std::move(k)};}Settlement SettlementBook::create(std::string id,std::string asset,std::string market,std::string currency,long long date,money::Fixed amount){auto it=config_.find({market,currency});if(it==config_.end())throw std::runtime_error("missing settlement convention");Settlement s{id,std::move(asset),currency,date,it->second.second.add_business_days(date,it->second.first.business_days),amount,false,false};items_.push_back(s);return s;}void SettlementBook::settle(const std::string&id){auto it=std::find_if(items_.begin(),items_.end(),[&](auto&x){return x.id==id;});if(it==items_.end())throw std::out_of_range("settlement");it->settled=true;it->failed=false;}void SettlementBook::mark_failures(long long now){for(auto&x:items_)if(!x.settled&&now>x.due_date)x.failed=true;}void ReviewQueue::quarantine(ReviewItem x){if(x.id.empty()||x.reason.empty())throw std::invalid_argument("review item");items_.push_back(std::move(x));}}
